('7248ec79-f22e-411d-90fc-4946fdeb027b','a395a429-3da6-4498-94e8-5ea73b231b69','SELECT branch, SUM(SAFE_CAST(REGEXP_REPLACE(Amount_Due, r''[^0-9.]'', '''') AS FLOAT64)) AS total_pending_due, SUM(SAFE_CAST(REGEXP_REPLACE(Amount_Collected, r''[^0-9.]'', '''') AS FLOAT64)) AS total_collected, ROUND(SAFE_DIVIDE(SUM(SAFE_CAST(REGEXP_REPLACE(Amount_Collected, r''[^0-9.]'', '''') AS FLOAT64)), SUM(SAFE_CAST(REGEXP_REPLACE(Actual_Revenue, r''[^0-9.]'', '''') AS FLOAT64))) * 100, 2) AS collection_pct FROM `tenms-userdb.english_centre.offline_admissions_gsheet_v3` GROUP BY branch ORDER BY total_pending_due DESC LIMIT 1000;
;
