('191c8550-7b60-4478-ae6a-662d7d14b9f8','63fa4bb0-b02f-4e96-9888-808c972f732f','SELECT branch, COUNT(DISTINCT contact) AS registrations, COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END) AS attendance, COUNT(DISTINCT CASE WHEN admission_date IS NOT NULL THEN contact END) AS admissions, ROUND(SAFE_DIVIDE(COUNT(DISTINCT CASE WHEN admission_date IS NOT NULL THEN contact END), COUNT(DISTINCT contact)) * 100, 2) AS reg_to_admission_pct, ROUND(SAFE_DIVIDE(COUNT(DISTINCT CASE WHEN admission_date IS NOT NULL THEN contact END), COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END)) * 100, 2) AS ata_pct FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE submission_date >= DATE ''2026-01-01'' AND submission_date < DATE ''2027-01-01'' GROUP BY branch ORDER BY ata_pct DESC, reg_to_admission_pct DESC LIMIT 1000;
;
